const fs=require('fs');
const lines=fs.readFileSync('src/components/DeploymentsView.tsx','utf8').split(/\r?\n/).slice(285,628);
let balance=0;
lines.forEach((line,idx)=>{
  const opens=(line.match(/<div\b/g)||[]).length;
  const closes=(line.match(/<\/div>/g)||[]).length;
  balance += opens - closes;
  if (opens || closes || idx > 320) {
    console.log(String(idx+286).padStart(4), balance, line.trim());
  }
});
